/* ══════════════════════════════════════════════
   audio.js — Road Rash Runner
   Engine sounds, SFX, background/menu music,
   weather ambient audio, volume buses.
══════════════════════════════════════════════ */

/* ══════════════════════════════════════════════
   AUDIO
══════════════════════════════════════════════ */
let AC,engOsc,engGain,engNoiseNode,engNoiseGain,engFilter;
let masterGain=null; // single mute point for ALL sounds
let engineBus=null;  // gain node for engine/continuous sounds (slider 1)
let sfxBus=null;     // gain node for SFX sounds — coin, moo, shield, etc. (slider 2)
let bgBus=null;      // gain node for background music (slider 3)
let weatherBus=null; // gain node for weather ambient sounds (slider 4)
let almostDeadBus=null; // direct path to AC.destination — bypasses masterGain mute
let engineBusVol=loadLS('rr_vol_engine',1.0);
let sfxBusVol=loadLS('rr_vol_sfx',1.0);
let bgBusVol=loadLS('rr_vol_bg',1.0);
let weatherBusVol=loadLS('rr_vol_wx',1.0);
let _initACRunning=false; // re-entrancy guard
function initAC(){
  if(_initACRunning)return;
  _initACRunning=true;
  if(!AC){try{AC=new(window.AudioContext||window.webkitAudioContext)();}catch(e){_initACRunning=false;return;}}
  // iOS suspends AudioContext aggressively — resume on every interaction
  try{if(AC.state==='suspended')AC.resume();}catch(e){}
  if(!masterGain){
    masterGain=AC.createGain();
    masterGain.gain.value=bgMuted?0:1;
    masterGain.connect(AC.destination);
  }
  if(!engineBus){
    engineBus=AC.createGain();
    engineBus.gain.value=engineBusVol;
    engineBus.connect(masterGain);
  }
  if(!sfxBus){
    sfxBus=AC.createGain();
    sfxBus.gain.value=sfxBusVol;
    sfxBus.connect(masterGain);
  }
  if(!bgBus){
    bgBus=AC.createGain();
    bgBus.gain.value=bgBusVol;
    bgBus.connect(masterGain);
  }
  if(!weatherBus){
    weatherBus=AC.createGain();
    weatherBus.gain.value=weatherBusVol;
    weatherBus.connect(masterGain);
  }
  if(!almostDeadBus){
    almostDeadBus=AC.createGain();
    almostDeadBus.gain.value=1.0;
    almostDeadBus.connect(AC.destination); // direct — never muted
  }
  _initACRunning=false;
  // On first successful AC unlock: fire pending splash sounds then start menu music.
  // Use setTimeout(0) to defer out of the current call stack — prevents re-entrant
  // initAC→startMenuMusic→_masterGain→initAC→startMenuMusic infinite loops.
  if(AC.state!=='suspended'){
    if(splashWhooshPending){_playSplashWhoosh();splashWhooshPending=false;}
    if(splashLaunchPending){_playSplashLaunch();splashLaunchPending=false;}
    const menuScreen=(gst===ST.SPLASH||gst===ST.INTRO||gst===ST.HOWTO||gst===ST.STATS||gst===ST.SHOP||gst===ST.GAMEOVER);
    if(menuScreen&&!menuMusicActive){
      setTimeout(()=>{if(!menuMusicActive)startMenuMusic();},0);
    }
  }
}
// iOS re-suspend fix: resume AudioContext on every document touchstart
document.addEventListener('touchstart',()=>{if(AC&&AC.state==='suspended')AC.resume();},{passive:true,capture:true});

// ── Realistic multi-layered engine ────────────────────
function startEngine(){
  if(!AC||engOsc)return;
  initAC(); // ensure masterGain exists
  const t=AC.currentTime;

  // ── Layer 1: fundamental rumble (sawtooth through lowpass) ──
  engOsc=AC.createOscillator();
  engFilter=AC.createBiquadFilter();
  engFilter.type='lowpass'; engFilter.frequency.value=320; engFilter.Q.value=1.8;
  engOsc.type='sawtooth'; engOsc.frequency.value=55;

  // ── Layer 2: 2nd harmonic with slight detune for richness ──
  const osc2=AC.createOscillator(),g2=AC.createGain();
  osc2.type='sawtooth'; osc2.frequency.value=110; osc2.detune.value=8;
  g2.gain.value=0.35;

  // ── Layer 3: 3rd harmonic (gives the "growl") ──
  const osc3=AC.createOscillator(),g3=AC.createGain();
  osc3.type='square'; osc3.frequency.value=165; osc3.detune.value=-6;
  g3.gain.value=0.18;

  // ── Layer 4: white noise through narrow bandpass (tyre/road texture) ──
  try{
    const sr=AC.sampleRate,dur=3,n=sr*dur;
    const buf=AC.createBuffer(1,n,sr),d=buf.getChannelData(0);
    for(let i=0;i<n;i++)d[i]=Math.random()*2-1;
    engNoiseNode=AC.createBufferSource(); engNoiseNode.buffer=buf; engNoiseNode.loop=true;
    const nf=AC.createBiquadFilter(); nf.type='bandpass'; nf.frequency.value=180; nf.Q.value=2.5;
    engNoiseGain=AC.createGain(); engNoiseGain.gain.value=0.07;
    engNoiseNode.connect(nf); nf.connect(engNoiseGain); engNoiseGain.connect(engineBus||masterGain);
    engNoiseNode.start(t);
  }catch(e){}

  // ── LFO: cylinder-fire "chug" modulation on main gain ──
  const lfo=AC.createOscillator(),lfoG=AC.createGain();
  lfo.type='sine'; lfo.frequency.value=26; // ~1600 RPM feel
  lfoG.gain.value=0.018;
  lfo.connect(lfoG);

  engGain=AC.createGain(); engGain.gain.value=0.18;
  lfoG.connect(engGain.gain);

  osc2.connect(g2); g2.connect(engFilter);
  osc3.connect(g3); g3.connect(engFilter);
  engOsc.connect(engFilter);
  engFilter.connect(engGain);
  engGain.connect(engineBus||masterGain);

  engOsc.start(t); osc2.start(t); osc3.start(t); lfo.start(t);
  // store extra oscillators for cleanup
  engOsc._extras=[osc2,osc3,lfo];
}
function stopEngine(){
  try{
    if(engOsc){
      (engOsc._extras||[]).forEach(o=>{try{o.stop();}catch(e){}});
      engOsc.stop(); engOsc=null; engGain=null; engFilter=null;
    }
    if(engNoiseNode){engNoiseNode.stop();engNoiseNode=null;engNoiseGain=null;}
  }catch(e){}
}
function tickEngine(){
  if(!engOsc||!engGain||!engFilter)return;
  // Pitch: rises with speed (realistic RPM increase)
  const rpm=55+baseSpd*6.5;
  engOsc.frequency.value=rpm;
  if(engOsc._extras){
    engOsc._extras[0].frequency.value=rpm*2;
    engOsc._extras[1].frequency.value=rpm*3;
    engOsc._extras[2].frequency.value=rpm*0.47; // LFO chug rate
  }
  // Volume: scales with speed — boosted so engine is clearly heard over background music
  engGain.gain.value=0.14+(baseSpd-3.5)*0.018;
  // Filter cutoff opens slightly with speed (louder harmonics at high speed)
  engFilter.frequency.value=280+baseSpd*22;
  // Noise road texture — also boosted
  if(engNoiseGain) engNoiseGain.gain.value=0.07+baseSpd*0.010;
}

function _dest(){ return sfxBus||masterGain||AC.destination; } // route SFX through sfxBus

// Pre-baked noise buffer — created once on first use, reused for all nz() calls.
// White-noise sounds are perceptually identical whether freshly generated or looped from a pre-bake.
let _noiseBuf=null;
function _getOrMakeNoiseBuf(){
  if(_noiseBuf)return _noiseBuf;
  const sr=AC.sampleRate,dur=2,n=sr*dur;
  const buf=AC.createBuffer(1,n,sr),d=buf.getChannelData(0);
  for(let i=0;i<n;i++)d[i]=Math.random()*2-1;
  _noiseBuf=buf;
  return buf;
}

/* ══════════════════════════════════════════════
   ALMOST DEAD — silence all, heartbeat direct
══════════════════════════════════════════════ */
function startAlmostDead(){
  if(!AC){return;} initAC();
  const t=AC.currentTime;
  // Ramp ALL audio to silence quickly — 40ms time-constant
  if(masterGain) masterGain.gain.cancelScheduledValues(t);
  if(masterGain) masterGain.gain.setTargetAtTime(0.0,t,0.04);
  // Heartbeat is routed through almostDeadBus → AC.destination (bypasses masterGain)
  _playHeartbeatDirect();
}

function stopAlmostDead(){
  if(!AC){return;}
  const t=AC.currentTime;
  const vol=bgMuted?0:1;
  if(masterGain){
    masterGain.gain.cancelScheduledValues(t);
    masterGain.gain.setTargetAtTime(vol,t,0.08); // restore over 80ms
  }
}

function _playHeartbeatDirect(){
  if(!AC||!almostDeadBus)return;
  const t=AC.currentTime;
  const _beat=(delay,freq,vol)=>{
    const o=AC.createOscillator(),g=AC.createGain();
    o.type='sine';
    o.frequency.setValueAtTime(freq,t+delay);
    o.frequency.exponentialRampToValueAtTime(freq*0.28,t+delay+0.22);
    g.gain.setValueAtTime(0,t+delay);
    g.gain.linearRampToValueAtTime(vol,t+delay+0.014);
    g.gain.exponentialRampToValueAtTime(0.001,t+delay+0.28);
    o.connect(g);g.connect(almostDeadBus);
    o.start(t+delay);o.stop(t+delay+0.32);
    // Low-frequency noise thud for body
    try{
      const src=AC.createBufferSource();src.buffer=_getOrMakeNoiseBuf();
      const f=AC.createBiquadFilter();f.type='lowpass';f.frequency.value=78;
      const gn=AC.createGain();
      gn.gain.setValueAtTime(vol*0.42,t+delay);
      gn.gain.exponentialRampToValueAtTime(0.001,t+delay+0.18);
      src.connect(f);f.connect(gn);gn.connect(almostDeadBus);
      src.start(t+delay);src.stop(t+delay+0.22);
    }catch(e){}
  };
  // Three LUB-DUB heartbeats spread across 750ms window
  _beat(0.02, 64, 0.95); // LUB 1 — dominant
  _beat(0.19, 52, 0.62); // DUB 1 — softer
  _beat(0.38, 64, 0.90); // LUB 2
  _beat(0.54, 52, 0.60); // DUB 2
  _beat(0.66, 64, 0.80); // LUB 3 — fading out as effect ends
  _beat(0.73, 52, 0.45); // DUB 3
}

function snd(type){
  if(!AC)return; initAC(); const t=AC.currentTime;
  const mk=(freq,tp,dur,vol,fe,delay)=>{
    const st=t+(delay||0),o=AC.createOscillator(),g=AC.createGain();
    o.type=tp||'sine';o.frequency.setValueAtTime(freq,st);
    if(fe)o.frequency.exponentialRampToValueAtTime(fe,st+dur*0.88);
    g.gain.setValueAtTime(vol||0.2,st);g.gain.exponentialRampToValueAtTime(0.001,st+dur);
    o.connect(g);g.connect(_dest());o.start(st);o.stop(st+dur+0.02);
  };
  const nz=(dur,vol,fq)=>{
    try{
      const src=AC.createBufferSource();src.buffer=_getOrMakeNoiseBuf();
      const f=AC.createBiquadFilter();f.type='bandpass';f.frequency.value=fq||380;
      const g=AC.createGain();g.gain.setValueAtTime(vol,t);g.gain.exponentialRampToValueAtTime(0.001,t+dur);
      src.connect(f);f.connect(g);g.connect(_dest());src.start(t);src.stop(t+dur+0.02);
    }catch(e){}
  };
  switch(type){
    case 'switch':   mk(640,'sine',0.07,0.14,320);break;
    case 'jump':     mk(240,'sine',0.26,0.22,740);break;
    case 'land':     mk(200,'sine',0.17,0.30,55);break;
    case 'crash':    nz(0.75,0.60,380);mk(115,'sine',0.40,0.70,28);break;
    case 'bloodcrash':nz(0.65,0.55,320);mk(100,'sine',0.32,0.65,25);mk(180,'sawtooth',0.45,0.22,75,0.10);break;
    case 'moo':{
      const o=AC.createOscillator(),g=AC.createGain(),f=AC.createBiquadFilter();
      o.type='sawtooth';o.frequency.setValueAtTime(132,t);o.frequency.setValueAtTime(112,t+0.18);o.frequency.setValueAtTime(130,t+0.38);
      g.gain.setValueAtTime(0,t);g.gain.linearRampToValueAtTime(0.28,t+0.07);g.gain.setValueAtTime(0.28,t+0.38);g.gain.exponentialRampToValueAtTime(0.001,t+0.64);
      f.type='lowpass';f.frequency.value=580;o.connect(f);f.connect(g);g.connect(_dest());o.start(t);o.stop(t+0.70);break;
    }
    case 'speedup':  [0,4,7,12].forEach((s,i)=>mk(440*Math.pow(2,s/12),'sine',0.20,0.18,null,i*0.08));break;
    case 'extralife':[0,4,7,12,16].forEach((s,i)=>mk(523*Math.pow(2,s/12),'sine',0.22,0.18,null,i*0.09));break;
    case 'coin':     mk(1400,'sine',0.10,0.13,2000);break;
    case 'powerup':  [0,7,12,19].forEach((s,i)=>mk(440*Math.pow(2,s/12),'sine',0.15,0.18,null,i*0.05));break;
    case 'nearmiss': nz(0.09,0.18,900);mk(320,'sawtooth',0.08,0.10,640);break;
    case 'comboUp':  [0,7,12].forEach((s,i)=>mk(660*Math.pow(2,s/12),'sine',0.16,0.22,null,i*0.06));break;
    case 'combo3':   [0,4,7,12,16].forEach((s,i)=>mk(660*Math.pow(2,s/12),'sine',0.18,0.28,null,i*0.05));nz(0.12,0.10,1100);break;
    case 'combo4':   [0,4,7,12,16,19,24].forEach((s,i)=>mk(880*Math.pow(2,s/12),'sawtooth',0.18,0.28,null,i*0.04));nz(0.20,0.18,1400);break;
    case 'saved':    mk(600,'sine',0.05,0.35,1800);mk(900,'sine',0.22,0.30,2200,0.06);nz(0.10,0.12,1800);break;
    case 'newRecord':[0,4,7,12,16,19,24].forEach((s,i)=>mk(523*Math.pow(2,s/12),'sine',0.25,0.22,null,i*0.06));break;
    case 'bossAppear':nz(0.35,0.45,280);mk(80,'sawtooth',0.55,0.55,50);mk(100,'sawtooth',0.40,0.40,40,0.20);break;
    case 'bossDefeated':[0,4,7,12,16,19,24,28].forEach((s,i)=>mk(440*Math.pow(2,s/12),'sine',0.22,0.22,null,i*0.05));break;
    case 'missionComplete':[0,4,7,12,16,19].forEach((s,i)=>mk(660*Math.pow(2,s/12),'sine',0.20,0.22,null,i*0.07));break;
    case 'shieldBlock':mk(500,'square',0.20,0.22,1100);nz(0.12,0.12,1400);break;
    case 'buy':      [0,4,7,12,16,19].forEach((s,i)=>mk(440*Math.pow(2,s/12),'sine',0.18,0.18,null,i*0.06));break;
    case 'deny':     mk(200,'square',0.18,0.15,100);break;
    case 'nitroOn':  [0,4,7,12,16].forEach((s,i)=>mk(880*Math.pow(2,s/12),'sine',0.12,0.16,null,i*0.04));break;
    // ── Machine Gun sounds ───────────────────────────────────────────────────
    case 'gunEquip':
      // Short rising two-tone — two sine oscillators stepping up in pitch
      mk(440,'sine',0.14,0.22,880);
      mk(660,'sine',0.12,0.18,1320,0.13);
      break;
    case 'gunFire':{
      // ── Bomb launch whoosh — rising whistle + air-rush ──
      // Gives the arc: whoosh → (travel) → BOOM, making the delay feel intentional
      try{
        const _sr=AC.sampleRate;
        // Rising whistle tone: sine sweep 180Hz → 900Hz over 0.22s
        {const _o=AC.createOscillator(),_g=AC.createGain();
        _o.type='sine';
        _o.frequency.setValueAtTime(180,t);
        _o.frequency.exponentialRampToValueAtTime(900,t+0.22);
        _g.gain.setValueAtTime(0,t);
        _g.gain.linearRampToValueAtTime(0.28,t+0.05);   // fast attack
        _g.gain.exponentialRampToValueAtTime(0.001,t+0.22); // fade as it flies
        _o.connect(_g);_g.connect(_dest());_o.start(t);_o.stop(t+0.24);}
        // Air rush — bandpass noise, rises in pitch (whoosh character)
        {const _n=Math.ceil(_sr*0.20),_buf=AC.createBuffer(1,_n,_sr),_d=_buf.getChannelData(0);
        for(let i=0;i<_n;i++)_d[i]=(Math.random()*2-1);
        const _src=AC.createBufferSource();_src.buffer=_buf;
        const _f=AC.createBiquadFilter();_f.type='bandpass';_f.frequency.value=1200;_f.Q.value=1.8;
        _f.frequency.setValueAtTime(600,t);
        _f.frequency.exponentialRampToValueAtTime(2400,t+0.20);
        const _g=AC.createGain();
        _g.gain.setValueAtTime(0.38,t);_g.gain.exponentialRampToValueAtTime(0.001,t+0.20);
        _src.connect(_f);_f.connect(_g);_g.connect(_dest());_src.start(t);_src.stop(t+0.22);}
        // Soft thump on launch — gives weight to the launch moment
        {const _o=AC.createOscillator(),_g=AC.createGain();
        _o.type='sine';_o.frequency.setValueAtTime(90,t);
        _o.frequency.exponentialRampToValueAtTime(30,t+0.08);
        _g.gain.setValueAtTime(0.40,t);_g.gain.exponentialRampToValueAtTime(0.001,t+0.08);
        _o.connect(_g);_g.connect(_dest());_o.start(t);_o.stop(t+0.10);}
      }catch(e){}
      break;}
    case 'gunHit':
    case 'bombBlast':{
      // ── Loud bomb explosion — 4-layer synthesis ──
      try{
        const _sr=AC.sampleRate;
        // Layer 1: Sharp crack transient — full spectrum noise, 80ms, very loud attack
        {const _n=Math.ceil(_sr*0.08),_buf=AC.createBuffer(1,_n,_sr),_d=_buf.getChannelData(0);
        for(let i=0;i<_n;i++)_d[i]=(Math.random()*2-1);
        const _src=AC.createBufferSource();_src.buffer=_buf;
        const _f=AC.createBiquadFilter();_f.type='highpass';_f.frequency.value=800;
        const _g=AC.createGain();
        _g.gain.setValueAtTime(0.90,t);_g.gain.exponentialRampToValueAtTime(0.001,t+0.08);
        _src.connect(_f);_f.connect(_g);_g.connect(_dest());_src.start(t);_src.stop(t+0.10);}
        // Layer 2: Deep bass thud — low noise through lowpass, 450ms
        {const _n=Math.ceil(_sr*0.45),_buf=AC.createBuffer(1,_n,_sr),_d=_buf.getChannelData(0);
        for(let i=0;i<_n;i++)_d[i]=(Math.random()*2-1);
        const _src=AC.createBufferSource();_src.buffer=_buf;
        const _f=AC.createBiquadFilter();_f.type='lowpass';_f.frequency.value=180;_f.Q.value=2.0;
        const _g=AC.createGain();
        _g.gain.setValueAtTime(0.80,t);_g.gain.exponentialRampToValueAtTime(0.001,t+0.45);
        _src.connect(_f);_f.connect(_g);_g.connect(_dest());_src.start(t);_src.stop(t+0.47);}
        // Layer 3: Mid rumble body — bandpass noise, 600ms
        {const _n=Math.ceil(_sr*0.60),_buf=AC.createBuffer(1,_n,_sr),_d=_buf.getChannelData(0);
        for(let i=0;i<_n;i++)_d[i]=(Math.random()*2-1);
        const _src=AC.createBufferSource();_src.buffer=_buf;
        const _f=AC.createBiquadFilter();_f.type='bandpass';_f.frequency.value=320;_f.Q.value=0.5;
        const _g=AC.createGain();
        _g.gain.setValueAtTime(0.55,t+0.03);_g.gain.exponentialRampToValueAtTime(0.001,t+0.60);
        _src.connect(_f);_f.connect(_g);_g.connect(_dest());_src.start(t+0.03);_src.stop(t+0.62);}
      }catch(e){}
      // Layer 4: Sub-bass boom — sine sweep 55Hz→18Hz over 0.7s (felt as much as heard)
      mk(55,'sine',0.70,0.85,18);
      // Layer 5: Resonant body tone — short sine at 90Hz, decays 300ms
      mk(90,'sine',0.30,0.55,30,0.04);
      break;}
    case 'gunHitCattle':{
      // Same bomb blast but slightly deeper for the meatier cattle hit
      try{
        const _sr=AC.sampleRate;
        {const _n=Math.ceil(_sr*0.08),_buf=AC.createBuffer(1,_n,_sr),_d=_buf.getChannelData(0);
        for(let i=0;i<_n;i++)_d[i]=(Math.random()*2-1);
        const _src=AC.createBufferSource();_src.buffer=_buf;
        const _f=AC.createBiquadFilter();_f.type='highpass';_f.frequency.value=600;
        const _g=AC.createGain();
        _g.gain.setValueAtTime(0.85,t);_g.gain.exponentialRampToValueAtTime(0.001,t+0.10);
        _src.connect(_f);_f.connect(_g);_g.connect(_dest());_src.start(t);_src.stop(t+0.12);}
        {const _n=Math.ceil(_sr*0.55),_buf=AC.createBuffer(1,_n,_sr),_d=_buf.getChannelData(0);
        for(let i=0;i<_n;i++)_d[i]=(Math.random()*2-1);
        const _src=AC.createBufferSource();_src.buffer=_buf;
        const _f=AC.createBiquadFilter();_f.type='lowpass';_f.frequency.value=140;_f.Q.value=2.5;
        const _g=AC.createGain();
        _g.gain.setValueAtTime(0.90,t);_g.gain.exponentialRampToValueAtTime(0.001,t+0.55);
        _src.connect(_f);_f.connect(_g);_g.connect(_dest());_src.start(t);_src.stop(t+0.57);}
        {const _n=Math.ceil(_sr*0.65),_buf=AC.createBuffer(1,_n,_sr),_d=_buf.getChannelData(0);
        for(let i=0;i<_n;i++)_d[i]=(Math.random()*2-1);
        const _src=AC.createBufferSource();_src.buffer=_buf;
        const _f=AC.createBiquadFilter();_f.type='bandpass';_f.frequency.value=260;_f.Q.value=0.6;
        const _g=AC.createGain();
        _g.gain.setValueAtTime(0.60,t+0.04);_g.gain.exponentialRampToValueAtTime(0.001,t+0.65);
        _src.connect(_f);_f.connect(_g);_g.connect(_dest());_src.start(t+0.04);_src.stop(t+0.67);}
      }catch(e){}
      mk(45,'sine',0.80,0.90,16);
      mk(75,'sine',0.35,0.60,28,0.05);
      break;}
    case 'gunPenalty':
      // Three descending sine notes — warning tones
      mk(880,'sine',0.12,0.22,null,0);
      mk(660,'sine',0.12,0.22,null,0.11);
      mk(440,'sine',0.14,0.22,null,0.22);
      break;
    case 'cheer': {
      // Crowd cheer — rapid noise bursts layering up like applause
      const _cheerDur = 1.6;
      try {
        for(let _ci=0; _ci<10; _ci++){
          const _cd = _ci * 0.045;
          const _csrc = AC.createBufferSource();
          _csrc.buffer = _getOrMakeNoiseBuf();
          const _cf = AC.createBiquadFilter();
          _cf.type = 'bandpass';
          _cf.frequency.value = 500 + _ci * 130;
          _cf.Q.value = 0.4;
          const _cg = AC.createGain();
          _cg.gain.setValueAtTime(0, t + _cd);
          _cg.gain.linearRampToValueAtTime(0.16 + _ci * 0.018, t + _cd + 0.07);
          _cg.gain.exponentialRampToValueAtTime(0.001, t + _cd + _cheerDur);
          _csrc.connect(_cf); _cf.connect(_cg); _cg.connect(_dest());
          _csrc.start(t + _cd); _csrc.stop(t + _cd + _cheerDur + 0.05);
        }
      } catch(e){}
      // Rising fanfare notes
      [0,4,7,12,16,19,24,28].forEach((s,i) => mk(523*Math.pow(2,s/12),'sine',0.28,0.14,null,i*0.035));
      break;
    }
    case 'certifiedDriver': {
      // Triumphant heroic fanfare — ascending major chord sweep + sub-bass thud + noise swell
      try{
        // Rising arpeggio — 7 sine notes sweeping up
        [0,4,7,12,16,19,24].forEach((s,i)=>mk(523*Math.pow(2,s/12),'sine',0.42,0.24,null,i*0.038));
        // Second chord layer — triangle wave, slightly delayed, warmer overtone
        [0,7,12,19].forEach((s,i)=>mk(784*Math.pow(2,s/12),'triangle',0.32,0.20,null,0.30+i*0.052));
        // Sub-bass punch — deep sine thud on the downbeat
        mk(55,'sine',0.60,0.75,28,0.27);
        mk(80,'sine',0.40,0.50,35,0.30);
        // Noise swell — adds air and excitement
        nz(0.45,0.28,350);
        // Final sparkle — high frequency shimmer at the end
        [0,4,7,12].forEach((s,i)=>mk(2093*Math.pow(2,s/12),'sine',0.18,0.10,null,0.55+i*0.028));
      }catch(e){}
      break;
    }
    case 'tutRewind': {
      // Mechanical tape-reverse effect — descending sawtooth sweeps
      mk(300,'sawtooth',0.22,0.28,150);
      mk(220,'sawtooth',0.20,0.22,100,0.06);
      nz(0.18,0.12,600);
      break;
    }
  } // end switch
} // end snd()


/* ══════════════════════════════════════════════
   BACKGROUND MUSIC  (procedural, per theme)
══════════════════════════════════════════════ */
let bgMusicNodes=[],bgMusicGain=null,bgMusicTheme='',bgMuted=false;
let wxSndNodes=[],wxSndGain=null,wxSndType='';

function _masterGain(){
  // Use bgBus as the music bus so the background volume slider controls it
  if(!AC)return null;
  initAC(); // ensure masterGain created
  if(!bgMusicGain){bgMusicGain=AC.createGain();bgMusicGain.gain.value=1.0;bgMusicGain.connect(bgBus||masterGain);}
  return bgMusicGain;
}

function stopBgMusic(){
  bgMusicNodes.forEach(n=>{try{n.stop();}catch(e){}});
  bgMusicNodes=[];bgMusicTheme='';
  // Reset gain to full for menu music
  if(bgMusicGain) bgMusicGain.gain.setTargetAtTime(1.0,AC?AC.currentTime:0,0.3);
}
function stopWeatherSnd(){
  wxSndNodes.forEach(n=>{try{n.stop();}catch(e){}});
  wxSndNodes=[];wxSndType='';
  if(wxSndGain){try{wxSndGain.disconnect();}catch(e){} wxSndGain=null;}
}

// ── Generative music engine ─────────────────────
// Synthwave base + progressive intensity layers unlocked by stage tier.
// Tier is driven by stageNum (global), so intensity survives theme cycling.
// Tier 1 (stages 1-3):  kick + bass + pad
// Tier 2 (stages 4-6):  + arpeggio  (8th-note synth riff)
// Tier 3 (stages 7-9):  + hi-hat    (offbeat noise bursts)
// Tier 4 (stages 10+):  + lead melody (catchy square-wave hook)
//
// Each theme gets a different major chord root so there's musical variety
// as the environment changes while always sounding upbeat:
//   city    → C major  (bright, urban)
//   highway → A major  (open-road drive)
//   desert  → G major  (warm, energetic)
//   night   → E major  (electric, intense)
function startBgMusic(theme){
  if(!AC||bgMusicTheme===theme)return;
  stopBgMusic();bgMusicTheme=theme;
  const mg=_masterGain();if(!mg)return;
  const t=AC.currentTime;

  // Intensity tier — does NOT reset when theme cycles at stage 13+
  const tier=stageNum<=3?1:stageNum<=6?2:stageNum<=9?3:4;
  // BPM scales with tier: 118 → 126 → 134 → 142
  const bpm=110+tier*8;
  const beat=60/bpm; // seconds per beat

  // Major chord roots per theme (root, third, fifth)
  const CHORDS={
    city:   [261.63,329.63,392.00], // C4 E4 G4
    highway:[220.00,277.18,329.63], // A3 C#4 E4
    desert: [196.00,246.94,293.66], // G3 B3 D4
    night:  [164.81,207.65,246.94], // E3 G#3 B3
  };
  const chord=CHORDS[theme]||CHORDS.city;
  const [cRoot,cThird,cFifth]=chord;

  // ── LAYER 1: Kick drum — punchy 4-on-the-floor (always active) ──────────
  (function kick(){
    if(bgMusicTheme!==theme)return;
    try{
      const ko=AC.createOscillator(),kg=AC.createGain();
      ko.type='sine';
      ko.frequency.setValueAtTime(115,AC.currentTime);
      ko.frequency.exponentialRampToValueAtTime(38,AC.currentTime+beat*0.20);
      kg.gain.setValueAtTime(0.55,AC.currentTime);
      kg.gain.exponentialRampToValueAtTime(0.001,AC.currentTime+beat*0.42);
      ko.connect(kg);kg.connect(mg);ko.start();ko.stop(AC.currentTime+beat*0.46);
    }catch(e){}
    setTimeout(kick,beat*1000);
  })();

  // ── LAYER 2: Synth bass — sawtooth through resonant lowpass (always) ─────
  // Walks root→root→fifth→root pattern for classic synthwave drive
  const bassNotes=[
    cRoot/2, cRoot/2, cFifth/2, cRoot/2,
    cRoot/2, cThird/2, cFifth/2, cRoot/2
  ];
  let bassIdx=0;
  (function bassNote(){
    if(bgMusicTheme!==theme)return;
    try{
      const o=AC.createOscillator(),g=AC.createGain(),flt=AC.createBiquadFilter();
      o.type='sawtooth';
      o.frequency.value=bassNotes[bassIdx%bassNotes.length];
      bassIdx++;
      flt.type='lowpass';flt.frequency.value=480+tier*70;flt.Q.value=4.5;
      g.gain.setValueAtTime(0.26,AC.currentTime);
      g.gain.exponentialRampToValueAtTime(0.001,AC.currentTime+beat*0.80);
      o.connect(g);g.connect(flt);flt.connect(mg);
      o.start();o.stop(AC.currentTime+beat*0.85);
    }catch(e){}
    setTimeout(bassNote,beat*1000);
  })();

  // ── LAYER 3: Chord pad — detuned sawtooth ensemble (always) ──────────────
  // Slight detune between voices gives the "fat" synthwave pad sound
  chord.forEach((f,i)=>{
    const o=AC.createOscillator(),g=AC.createGain(),flt=AC.createBiquadFilter();
    o.type='sawtooth';
    o.frequency.value=f;
    o.detune.value=(i-1)*9+(tier-1)*3; // widens with intensity
    flt.type='lowpass';flt.frequency.value=1600+tier*280;flt.Q.value=0.75;
    // Sidechain-pump LFO synced to kick rate
    const lfo=AC.createOscillator(),lG=AC.createGain();
    lfo.type='sine';lfo.frequency.value=bpm/60;
    lG.gain.value=0.011+tier*0.003;
    lfo.connect(lG);lG.connect(g.gain);
    g.gain.value=0.032+tier*0.006;
    o.connect(flt);flt.connect(g);g.connect(mg);
    o.start(t);lfo.start(t);
    bgMusicNodes.push(o,lfo);
  });

  // ── LAYER 4: Arpeggio — square wave, 8th notes (tier 2+, stages 4+) ─────
  if(tier>=2){
    // Ascending/descending arpeggio over the chord tones
    const arp=[
      cRoot*2, cThird*2, cFifth*2, cRoot*4,
      cFifth*2, cThird*2, cRoot*2, cThird*2
    ];
    let aIdx=0;
    const aSpd=beat/2; // 8th note
    (function arpStep(){
      if(bgMusicTheme!==theme)return;
      try{
        const o=AC.createOscillator(),g=AC.createGain(),flt=AC.createBiquadFilter();
        o.type='square';
        o.frequency.value=arp[aIdx%arp.length];
        aIdx++;
        flt.type='lowpass';flt.frequency.value=2600;flt.Q.value=1.4;
        g.gain.setValueAtTime(0.040+tier*0.006,AC.currentTime);
        g.gain.exponentialRampToValueAtTime(0.001,AC.currentTime+aSpd*0.62);
        o.connect(flt);flt.connect(g);g.connect(mg);
        o.start();o.stop(AC.currentTime+aSpd*0.68);
      }catch(e){}
      setTimeout(arpStep,aSpd*1000);
    })();
  }

  // ── LAYER 5: Hi-hat — highpass noise on off-beats (tier 3+, stages 7+) ──
  if(tier>=3){
    let hhPhase=0;
    (function hihat(){
      if(bgMusicTheme!==theme)return;
      hhPhase=(hhPhase+1)%2;
      // Louder on the backbeat (2nd half-beat), softer on the downbeat
      const vol=hhPhase===1?0.11:0.055;
      try{
        const sr=AC.sampleRate,n=Math.ceil(sr*0.055);
        const buf=AC.createBuffer(1,n,sr),d=buf.getChannelData(0);
        for(let i=0;i<n;i++)d[i]=Math.random()*2-1;
        const src=AC.createBufferSource();src.buffer=buf;
        const flt=AC.createBiquadFilter();flt.type='highpass';flt.frequency.value=7200;
        const g=AC.createGain();
        g.gain.setValueAtTime(vol,AC.currentTime);
        g.gain.exponentialRampToValueAtTime(0.001,AC.currentTime+0.042);
        src.connect(flt);flt.connect(g);g.connect(mg);
        src.start();src.stop(AC.currentTime+0.058);
      }catch(e){}
      setTimeout(hihat,beat*500); // every half-beat (8th note hi-hat grid)
    })();
  }

  // ── LAYER 6: Lead melody — catchy square hook (tier 4+, stages 10+) ──────
  if(tier>=4){
    // 9-note repeating riff that sits above the arpeggio
    const mel=[
      [cFifth*2,1],[cFifth*2,0.5],[cThird*2*Math.pow(2,2/12),0.5],
      [cFifth*2,1],[cRoot*4,1],
      [cThird*2,1],[cFifth*2,0.5],[cRoot*4,0.5],
      [cFifth*2,2]
    ];
    let mIdx=0;
    (function melStep(){
      if(bgMusicTheme!==theme)return;
      const [f,b]=mel[mIdx%mel.length];mIdx++;
      const dur=b*beat;
      try{
        const o=AC.createOscillator(),g=AC.createGain(),flt=AC.createBiquadFilter();
        o.type='square';
        o.frequency.value=f;
        flt.type='lowpass';flt.frequency.value=3400;flt.Q.value=2.0;
        g.gain.setValueAtTime(0.055,AC.currentTime);
        g.gain.exponentialRampToValueAtTime(0.001,AC.currentTime+dur*0.86);
        o.connect(flt);flt.connect(g);g.connect(mg);
        o.start();o.stop(AC.currentTime+dur*0.92);
      }catch(e){}
      setTimeout(melStep,dur*1000);
    })();
  }
}

// ── Weather ambient SFX ─────────────────────────
function startWeatherSnd(type){
  if(!AC||wxSndType===type)return;
  stopWeatherSnd();wxSndType=type;
  const mg=_masterGain();if(!mg)return;
  const t=AC.currentTime;
  wxSndGain=AC.createGain();wxSndGain.gain.value=0;wxSndGain.connect(weatherBus||masterGain);
  // Fade in
  wxSndGain.gain.linearRampToValueAtTime(1,t+1.2);

  if(type==='rain'){
    // White noise through bandpass — rainfall hiss
    try{
      const sr=AC.sampleRate,dur=4,n=sr*dur;
      const buf=AC.createBuffer(1,n,sr),d=buf.getChannelData(0);
      for(let i=0;i<n;i++)d[i]=Math.random()*2-1;
      const src=AC.createBufferSource();src.buffer=buf;src.loop=true;
      const f=AC.createBiquadFilter();f.type='bandpass';f.frequency.value=1800;f.Q.value=0.6;
      const g2=AC.createGain();g2.gain.value=0.30;
      src.connect(f);f.connect(g2);g2.connect(wxSndGain);src.start(t);
      wxSndNodes.push(src);
    }catch(e){}
    // Low rumble undertone
    const o=AC.createOscillator(),g=AC.createGain();
    o.type='sawtooth';o.frequency.value=55;g.gain.value=0.04;
    o.connect(g);g.connect(wxSndGain);o.start(t);wxSndNodes.push(o);

  } else if(type==='fog'){
    // Very low, slow drone — eerie
    [[60,'sine',0.055],[90,'sine',0.025],[47,'triangle',0.035]].forEach(([f,tp,v])=>{
      const o=AC.createOscillator(),g=AC.createGain();
      o.type=tp;o.frequency.value=f;g.gain.value=v;
      o.connect(g);g.connect(wxSndGain);o.start(t);wxSndNodes.push(o);
    });

  } else if(type==='dust'){
    // Sweeping noise + low wind rumble
    try{
      const sr=AC.sampleRate,dur=3,n=sr*dur;
      const buf=AC.createBuffer(1,n,sr),d=buf.getChannelData(0);
      for(let i=0;i<n;i++)d[i]=Math.random()*2-1;
      const src=AC.createBufferSource();src.buffer=buf;src.loop=true;
      const f=AC.createBiquadFilter();f.type='lowpass';f.frequency.value=520;
      const lfo=AC.createOscillator(),lG=AC.createGain();
      lfo.type='sine';lfo.frequency.value=0.18;lG.gain.value=280;
      lfo.connect(lG);lG.connect(f.frequency);
      const g2=AC.createGain();g2.gain.value=0.35;
      src.connect(f);f.connect(g2);g2.connect(wxSndGain);
      src.start(t);lfo.start(t);wxSndNodes.push(src,lfo);
    }catch(e){}

  } else if(type==='roadworks'){
    // Intermittent low thump drill
    const o=AC.createOscillator(),g=AC.createGain();
    o.type='square';o.frequency.value=48;g.gain.value=0.06;
    o.connect(g);g.connect(wxSndGain);o.start(t);wxSndNodes.push(o);
  }
}

function updateMusicForTheme(){
  if(gst!==ST.PLAYING&&gst!==ST.RESPAWNING)return;
  const theme=getEnvTheme();
  startBgMusic(theme);
  // Weather sound sync
  if(weatherType!=='clear'&&wxSndType!==weatherType) startWeatherSnd(weatherType);
  if(weatherType==='clear'&&wxSndType!=='') stopWeatherSnd();
  // During gameplay: keep background music quiet so engine is clearly audible
  // Lower still when weather is active (weather bus handles those sounds separately)
  if(bgMusicGain){
    const tgt=wxSndType?0.07:0.13;
    bgMusicGain.gain.setTargetAtTime(tgt,AC.currentTime,0.8);
  }
}

function toggleMute(){
  bgMuted=!bgMuted;
  const btn=document.getElementById('muteBtn');
  if(btn)btn.textContent=bgMuted?'🔇':'♪';
  btn?.classList.toggle('muted',bgMuted);
  // Sync .muted class on soundCtrlBtn so CSS EQ bars go flat
  document.getElementById('soundCtrlBtn')?.classList.toggle('muted',bgMuted);
  if(masterGain) masterGain.gain.setTargetAtTime(bgMuted?0:1,AC.currentTime,0.15);
}

/* ══════════════════════════════════════════════
   MENU MUSIC  (turbo_coin_toss.mp3 — stereo, looped)
   Plays on splash/intro/gameover screens.
   Stops when user taps Play.
══════════════════════════════════════════════ */
const _MENU_MUSIC_B64='';
let _menuMusicSrc=null; // BufferSourceNode for the MP3

function _b64ToArrayBuffer(b64){
  const bin=atob(b64),len=bin.length,buf=new ArrayBuffer(len),view=new Uint8Array(buf);
  for(let i=0;i<len;i++)view[i]=bin.charCodeAt(i);
  return buf;
}

function startMenuMusic(){
  if(!AC||menuMusicActive)return;
  initAC();
  const mg=_masterGain();if(!mg)return;
  menuMusicActive=true;
  AC.decodeAudioData(_b64ToArrayBuffer(_MENU_MUSIC_B64),function(decoded){
    if(!menuMusicActive)return; // stopped before decode finished
    try{
      _menuMusicSrc=AC.createBufferSource();
      _menuMusicSrc.buffer=decoded;
      _menuMusicSrc.loop=true;
      // Fade-in gain node — ramps from 0 to 1 over 3 seconds
      const fadeIn=AC.createGain();
      fadeIn.gain.setValueAtTime(0,AC.currentTime);
      fadeIn.gain.linearRampToValueAtTime(1.0,AC.currentTime+3.0);
      _menuMusicSrc.connect(fadeIn);
      fadeIn.connect(mg); // mg is bgMusicGain → bgBus → masterGain; stereo preserved
      _menuMusicSrc.start(0);
    }catch(e){}
  },function(e){console.warn('Menu music decode error',e);});
}

function stopMenuMusic(){
  menuMusicActive=false;
  if(_menuMusicSrc){try{_menuMusicSrc.stop();}catch(e){} _menuMusicSrc=null;}
  menuMusicNodes.forEach(n=>{try{n.stop();}catch(e){}});
  menuMusicNodes=[];
}


